function EvalToggleButtonGroupAlignment() {
  const [alignment, setAlignment] = useState<'left' | 'center' | 'right'>('left');

  return (
    <ToggleButtonGroup aria-label="Text alignment">
      <ToggleButton isSelected={alignment === 'left'} onChange={() => setAlignment('left')} aria-label="Align left">
        <AlignLeft size={16} />
      </ToggleButton>
      <ToggleButton isSelected={alignment === 'center'} onChange={() => setAlignment('center')} aria-label="Align center">
        <AlignCenter size={16} />
      </ToggleButton>
      <ToggleButton isSelected={alignment === 'right'} onChange={() => setAlignment('right')} aria-label="Align right">
        <AlignRight size={16} />
      </ToggleButton>
    </ToggleButtonGroup>
  );
}

