// ── calendar-date ─────────────────────────────────
type EvalCalendarDateValueType = Parameters<NonNullable<React.ComponentProps<typeof Calendar.Root>['onChange']>>[0];

function EvalCalendarDate() {
  const [selectedDate, setSelectedDate] = useState<EvalCalendarDateValueType | null>(null);

  return (
    <Column gap="s">
      <Text variant="heading" size="m">Select a date</Text>
      <Calendar.Root value={selectedDate} onChange={setSelectedDate}>
        <Calendar.Header>
          <Calendar.PreviousButton />
          <Calendar.Heading />
          <Calendar.NextButton />
        </Calendar.Header>
        <Calendar.Grid>
          <Calendar.GridHeader>{(day) => <Calendar.GridHeaderCell>{day}</Calendar.GridHeaderCell>}</Calendar.GridHeader>
          <Calendar.GridBody>{(date) => <Calendar.Cell date={date} />}</Calendar.GridBody>
        </Calendar.Grid>
      </Calendar.Root>
      {selectedDate && <Text color="muted" size="s">Selected: {selectedDate.toString()}</Text>}
    </Column>
  );
}

