// ── range-calendar-dates ──────────────────────────
type EvalRangeCalendarDatesValueType = Parameters<NonNullable<React.ComponentProps<typeof RangeCalendar.Root>['onChange']>>[0];

function EvalRangeCalendarDates() {
  const [value, setValue] = useState<EvalRangeCalendarDatesValueType | null>(null);

  return (
    <Column gap="s">
      <Text variant="heading" size="m">Select a date range</Text>
      <RangeCalendar.Root value={value} onChange={setValue}>
        <RangeCalendar.Header>
          <RangeCalendar.PreviousButton />
          <RangeCalendar.Heading />
          <RangeCalendar.NextButton />
        </RangeCalendar.Header>
        <RangeCalendar.Grid>
          <RangeCalendar.GridHeader>{(day) => <RangeCalendar.GridHeaderCell>{day}</RangeCalendar.GridHeaderCell>}</RangeCalendar.GridHeader>
          <RangeCalendar.GridBody>{(date) => <RangeCalendar.Cell date={date} />}</RangeCalendar.GridBody>
        </RangeCalendar.Grid>
      </RangeCalendar.Root>
      {value && (
        <Text color="muted" size="s">
          Selected: {value.start?.toString()} – {value.end?.toString()}
        </Text>
      )}
    </Column>
  );
}

// ── settings-page ─────────────────────────────────
function EvalSettingsPage() {
  return (
    <Column gap="l" style={{ maxWidth: 800, margin: '0 auto' }}>
      <Text variant="heading" size="m">Settings</Text>
      
      <Row gap="l">
        <Column>
          <Card.Root variant="elevated">
            <Card.Header>
              <Text variant="heading" size="s">Profile</Text>
            </Card.Header>
            <Card.Body>
              <TextField.Root isRequired>
                <TextField.Label>Name</TextField.Label>
                <TextField.Input placeholder="Jane Doe" />
              </TextField.Root>
            </Card.Body>
          </Card.Root>
        </Column>
        
        <Column>
          <Card.Root variant="elevated">
            <Card.Header>
              <Text variant="heading" size="s">Preferences</Text>
            </Card.Header>
            <Card.Body>
              <Select.Root defaultValue="system">
                <Select.Label>Theme</Select.Label>
                <Select.Trigger>
                  <Select.Value />
                  <Select.Icon />
                </Select.Trigger>
                <Select.Popover>
                  <Select.ListBox>
                    <Select.Item id="light">Light</Select.Item>
                    <Select.Item id="dark">Dark</Select.Item>
                    <Select.Item id="system">System</Select.Item>
                  </Select.ListBox>
                </Select.Popover>
              </Select.Root>
            </Card.Body>
          </Card.Root>
        </Column>
      </Row>
      
      <Row gap="m" justify="end">
        <Button variant="ghost">Cancel</Button>
        <Button variant="primary">Save</Button>
      </Row>
    </Column>
  );
}

